sync包
sync/atomic包
并发三个业务, 一起结束


cond := sync.NewCond(new(sync.Mutex))
wg := sync.WaitGroup{}
wg.Add(3)
wg1 := sync.WaitGroup{}
wg1.Add(3)
for i := 0; i &lt; 3; i++ {
    go func(i int) {
        defer wg1.Done()
        cond.L.Lock()
        fmt.Println(&quot;wait&quot;, i)          # 业务预处理
        wg.Done()
        cond.Wait()                     # 阻塞
        fmt.Println(&quot;done&quot;, i)          # 业务后续处理(要求所有业务预处理过)
        cond.L.Unlock()
    }(i)
}
wg.Wait()                               # 业务预处理完成

cond.L.Lock()
cond.Broadcast()                        # 处理业务后续
cond.L.Unlock()
wg1.Wait()                              # goroutine完成





异步

语句

语句是串行一致的(sequentially consistent)
串行一致基础上，语句会重排, 重排中可能穿插执行其它goroutine语句


t := map[string]int{
    &quot;a&quot;: 1
    &quot;b&quot;: 2
}
重排为
