func gen(done &lt;-chan struct{}, nums ...int) &lt;-chan int {
    out := make(chan int)
    go func() {
        defer close(out)
        for _, n := range nums {
            select {
            case out &lt;- n:
            case &lt;-done:
                return
            }
        }
    }()
    return out
}
func sq(done &lt;-chan struct{}, in &lt;-chan int) &lt;-chan int {
    out := make(chan int)
    go func() {
        defer close(out)
        for n := range in {
            select {
            case out &lt;- n * n:
            case &lt;-done:
                return
            }
        }
    }()
    return out
}
func merge(done &lt;-chan struct{}, cs ...&lt;-chan int) &lt;-chan int {
    # wg等cs数目个协程合并数据到out后，关闭out
    var wg sync.WaitGroup
    out := make(chan int)

    output := func(c &lt;-chan int) {
        for n := range c {
            select {
            case out &lt;- n:
            case &lt;-done:
            }
        }
        wg.Done()
    }

    wg.Add(len(cs))
    for _, c := range cs {
        go output(c)
    }

    go func() {
        wg.Wait()
        close(out)
    }()
    return out
}

func main() {
    done := make(chan struct{})
    defer close(done)

    for n := range sq(done, sq(done, gen(done, 2, 3))) {
        # gen产生维护数字chan, sq产生维护平方chan。三个chan
        # 三个goroutine done()时return, chan return时close()
        fmt.Println(n)
    }

    // 扇出
    in := gen(done, 2, 3)
    c1 := sq(done, in)
    c2 := sq(done, in)
    // 扇进
    for n := range merge(done, c1, c2) {
        fmt.Println(n)
    }
}



