func concurrent(done chan struct{}, fn func(), num int, ccu int, qps int) {     # num总数，ccu并行数，qps并发数
    interval := time.Duration(1e9/qps) * time.Nanosecond
    don := make(chan struct{}, 2)
    go func() {
        &lt;-done
        for i := 0; i &lt; ccu; i++ {
            don &lt;- struct{}{}
        }
    }()

    //
    tasks := make(chan struct{})
    go func() {
        var wg sync.WaitGroup
        wg.Add(num)
        for i := 0; i &lt; num; i++ {
            tasks &lt;- struct{}{}
            wg.Done()
            time.Sleep(interval)
        }
        wg.Wait()
        close(tasks)
    }()

    //
    var wg sync.WaitGroup
    wg.Add(ccu)
    for i := 0; i &lt; ccu; i++ {
        go func() {
            defer wg.Done()
            for range tasks {
                select {
                case &lt;-don:
                    return
                default:
                    fn()
                }
            }
        }()
    }
    wg.Wait()
}
