create or replace function change_type1()
returns int as
$body$
DECLARE
    r mongo_keys_type%rowtype;
    begin
    for r in select * from mongo_keys_type where type=&#039;number&#039;
    loop
        EXECUTE &#039;alter table &quot;&#039; || r.&quot;mongo_collection_name&quot; || &#039;&quot; alter &quot;&#039; || r.&quot;key&quot; || &#039;&quot; type decimal&#039;;
    END LOOP;
    return 0;
    end
$body$
