        const cls = index === activeIndex ? &#039;active&#039; : &#039;&#039;
        return (
          &lt;li key={index} className={cls} onClick={() =&gt; this.activate(index)}&gt;&lt;/li&gt;
        )
      })
      return (&lt;ul&gt;{lis}&lt;/ul&gt;)
    }
  }


