ReadWriteLock readWriteLock = new ReentrantReadWriteLock();
Lock readLock = readWriteLock.readLock();
Lock writeLock = readWriteLock.writeLock();
void read(Lock lock) {
    lock.lock()
    lock.unlock()
}
void write(Lock lock) {
    lock.lock()
    lock.unlock()
}
