乱序执行.content:
指令重排序
为什么

CPU快, 指令1阻塞时，指令2先执行


判断

代码不影响单线程最终一致性


例子，多线程


static int x = 0, y = 0;
static int a = 0, b = 0;
void main(){
    for (long i = 0; i &lt; Long.MAX_VALUE; i++&gt;) {
        x=0;
        y=0;
        a=0;
        b=0;
        CountDownLatch latch = new CountDownLatch(2);

        Thread one = new Thread(() -&gt; {
            public void run() {
                a = 1;
                x = b;
                latch.countDown();
            }
        });

        Thread other = new Thread(() -&gt; {
            public void run() {
                b = 1;
                y = a;
                latch.countDown();
            }
        });
        one.start();
        other.start();
        latch.await();
        if (x == 0 &amp;&amp; y == 0) {
            break;
        }

    }
}



